approach 1approach 2 <pre><code>func groupAnagrams(strs []string) [][]string {
    kv := map[[26]int][]string{}
    for _, word := range strs {
        counter := [26]int{}
        for i := 0; i &lt; len(word); i++ {
            key := word[i] - 'a'
            counter[key]++
        }
        kv[counter] = append(kv[counter], word)
    }
    res := make([][]string, 0, len(kv))
    for _, values := range kv {
        res = append(res, values)
    }
    return res
}
</code></pre> <pre><code>import (
    "slices"
)

func groupAnagrams(strs []string) [][]string {
    kv := map[string][]int{}
    for i, word := range strs {
        runes := []rune(word)
        slices.Sort(runes)
        key := string(runes)
        kv[key] = append(kv[key], i)
    }
    res := make([][]string, 0, len(kv))
    for _, indexes := range kv {
        subset := make([]string, len(indexes))
        for j, idx := range indexes {
            subset[j] = strs[idx]
        }
        res = append(res, subset)
    }
    return res
}
</code></pre>

routes/users.js<pre><code>const express = require('express')
const router = express.Router()

...

router
  .route('/:id')
  .get((req, res) =&gt; {
    console.log(req.user)
    res.send(`Get User With ID ${req.params.id}`)
}).put((req, res) =&gt; {
    res.send(`Update User With ID ${req.params.id}`)
}).delete((req, res) =&gt; {
    res.send(`Delete User With ID ${req.params.id}`)
})

const users = [{ name: "Kyle" }, { name: "Sally" }]
router.param("id", (req, res, next, id) =&gt; {
  req.user = users[id]
  next()
})

module.exports = router
</code></pre> <ul> <li><code>router.param('id', ...)</code>: A type of middleware that runs specifically when the URL contains the <code>id</code> parameter. This is useful for pre-loading data or performing validation across all routes that share the same path parameter.</li> <li><code>req.user = users[id]</code>: In this example, the middleware looks up the user in a local array using the provided <code>id</code> and attaches it to the <code>req</code> object, making it accessible in the subsequent route handlers (e.g., <code>console.log(req.user)</code>).</li> <li><code>next()</code>: Mandatory call to pass control to the next middleware or route handler in the stack.</li> </ul>
